+		t.Fatalf("ParseTranscript() got %d messages, want 1", len(transcript.Messages))
+	}
+
+	want := "part one\npart two"
+	if transcript.Messages[0].Content != want {
+		t.Errorf("Content = %q, want %q", transcript.Messages[0].Content, want)
+	}
+}
+
